// ─── Inputs ────────────────────────────────────────────────────────────
const allItems = $input.first().json
  ? [$input.first().json]
  : $input.all().map(i => i.json);
const salesRows = allItems.filter(i => i.shop_id);
const stockRows = allItems.filter(i => i.current_stock !== undefined);
const debtRows  = allItems.filter(i => i.debtor_name);

// ─── Detect report type ────────────────────────────────────────────────
const now        = new Date();
const today      = now.toISOString().split('T')[0];
const dayOfMonth = now.getDate();
const dayOfWeek  = now.getDay();
const type       = dayOfMonth === 1 ? 'monthly'
                 : dayOfWeek  === 6 ? 'weekly'
                 : 'daily';

// ─── Helpers ───────────────────────────────────────────────────────────
const SHOPS  = ['shop_a', 'shop_b', 'shop_c'];
const LABELS = { shop_a: 'Shop A', shop_b: 'Shop B', shop_c: 'Shop C' };
const BUDGET = 1200000;
const fmt    = n => Number(n).toLocaleString('en-BD');
const SEP    = '────────────────────────';

function shopStats(rows) {
  const result = {};
  for (const shop of SHOPS) {
    const s = rows.filter(r => r.shop_id === shop);
    result[shop] = {
      rev:    s.reduce((t, r) => t + Number(r.total_sale),   0),
      profit: s.reduce((t, r) => t + Number(r.total_profit), 0),
      units:  s.reduce((t, r) => t + Number(r.qty_sold),     0),
    };
  }
  return result;
}

function topProduct(rows) {
  const map = {};
  rows.forEach(r => {
    map[r.product_name] = (map[r.product_name] || 0) + Number(r.qty_sold);
  });
  return Object.entries(map).sort((a, b) => b[1] - a[1])[0] || ['N/A', 0];
}

function stockLines(rows) {
  if (!rows.length) return 'No stock data';
  return rows.map(r => {
    const ok = Number(r.current_stock) > Number(r.low_stock_alert);
    return `${ok ? '✅' : '⚠️'} ${r.product_name} — ${r.current_stock} units`;
  }).join('\n');
}

// ─── Debt section ──────────────────────────────────────────────────────
const unpaid    = debtRows.filter(r => r.status !== 'paid');
const paidToday = debtRows.filter(r =>
  (r.status === 'paid' || r.status === 'partial') && r.paid_date === today
);
const dueToday  = unpaid.filter(r => r.due_date === today);
const overdue   = unpaid.filter(r => r.due_date < today);

const tomorrow    = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toISOString().split('T')[0];
const dueTomorrow = unpaid.filter(r => r.due_date === tomorrowStr);

let debtMessage = '';

if (paidToday.length || dueToday.length || overdue.length || dueTomorrow.length) {
  const dateStr = now.toLocaleDateString('en-BD',
    { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
  debtMessage = `💰 *Debt Alert*\n_${dateStr}_\n${SEP}\n`;

  if (paidToday.length) {
    const collected = paidToday.reduce((t, r) => t + Number(r.amount_paid || r.amount_owed || 0), 0);
    debtMessage += `\n✅ *Paid Today — ৳ ${fmt(collected)}*\n`;
    debtMessage += paidToday.map(r => {
      const paid = Number(r.amount_paid || r.amount_owed || 0);
      const tag  = r.status === 'partial' ? ' _(partial)_' : ' _(settled)_';
      return `• ${r.debtor_name} — ৳ ${fmt(paid)}${tag}`;
    }).join('\n') + '\n';
  }

  if (dueToday.length) {
    debtMessage += `\n🔔 *Due Today*\n`;
    debtMessage += dueToday.map(r => {
      const remaining = Number(r.amount_owed || 0) - Number(r.amount_paid || 0);
      return `• ${r.debtor_name} — ৳ ${fmt(remaining)}`;
    }).join('\n') + '\n';
  }

  if (overdue.length) {
    debtMessage += `\n🚨 *Overdue*\n`;
    debtMessage += overdue.map(r => {
      const remaining = Number(r.amount_owed || 0) - Number(r.amount_paid || 0);
      const daysLate  = Math.floor((new Date(today) - new Date(r.due_date)) / (1000*60*60*24));
      return `• ${r.debtor_name} — ৳ ${fmt(remaining)} (${daysLate}d late)`;
    }).join('\n') + '\n';
  }

  if (dueTomorrow.length) {
    debtMessage += `\n📅 *Due Tomorrow*\n`;
    debtMessage += dueTomorrow.map(r => {
      const remaining = Number(r.amount_owed || 0) - Number(r.amount_paid || 0);
      return `• ${r.debtor_name} — ৳ ${fmt(remaining)}`;
    }).join('\n') + '\n';
  }

  const totalOwed = unpaid.reduce((t, r) =>
    t + Number(r.amount_owed || 0) - Number(r.amount_paid || 0), 0);
  debtMessage += `\n${SEP}\nTotal outstanding: ৳ ${fmt(totalOwed)}\n_${unpaid.length} open debt(s)_`;
}

// ─── DAILY ─────────────────────────────────────────────────────────────
let reportMessage = '';

if (type === 'daily') {
  const rows        = salesRows.filter(r => r.date === today);
  const stats       = shopStats(rows);
  const totalRev    = SHOPS.reduce((t, s) => t + stats[s].rev,    0);
  const totalProfit = SHOPS.reduce((t, s) => t + stats[s].profit, 0);
  const totalUnits  = SHOPS.reduce((t, s) => t + stats[s].units,  0);
  const dateStr     = now.toLocaleDateString('en-BD',
    { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

  let shopLines = '';
  for (const shop of SHOPS) {
    const shopRows = rows.filter(r => r.shop_id === shop);
    const top      = topProduct(shopRows);
    shopLines += `*${LABELS[shop]}*\n`
      + `Total Sales: ৳ ${fmt(stats[shop].rev)}\n`
      + `Total Profit: ৳ ${fmt(stats[shop].profit)}\n`
      + `Top Product: ${top[0]} — ${top[1]} units\n\n`;
  }

  // Debt summary for daily report
  const paidAmt = paidToday.reduce((t, r) => t + Number(r.amount_paid || r.amount_owed || 0), 0);
  const totalOwed = unpaid.reduce((t, r) =>
    t + Number(r.amount_owed || 0) - Number(r.amount_paid || 0), 0);
  const debtSummary = `Collected Today: ৳ ${fmt(paidAmt)}${paidToday.length ? ` (${paidToday.length} payment${paidToday.length>1?'s':''})` : ''}\n`
    + `Total Outstanding: ৳ ${fmt(totalOwed)} | Open: ${unpaid.length}${overdue.length ? ` | Overdue: ${overdue.length} ⚠️` : ''}`;

  reportMessage = `📊 *Daily Business Report*\n_${dateStr}_\n${SEP}\n\n`
    + shopLines
    + `*Combined Today*\n`
    + `Total Revenue: ৳ ${fmt(totalRev)}\n`
    + `Total Profit: ৳ ${fmt(totalProfit)}\n`
    + `Total Units Sold: ${totalUnits}\n${SEP}\n`
    + `*Stock Alerts*\n${stockLines(stockRows)}\n${SEP}\n`
    + `*Debt Summary*\n${debtSummary}\n${SEP}\n`
    + `_— Auto Report_`;
}

// ─── WEEKLY ────────────────────────────────────────────────────────────
else if (type === 'weekly') {
  const weekStart = new Date(now);
  weekStart.setDate(now.getDate() - dayOfWeek);
  weekStart.setHours(0, 0, 0, 0);
  const weekStartStr = weekStart.toISOString().split('T')[0];

  const rows        = salesRows.filter(r => r.date >= weekStartStr);
  const stats       = shopStats(rows);
  const totalRev    = SHOPS.reduce((t, s) => t + stats[s].rev,    0);
  const totalProfit = SHOPS.reduce((t, s) => t + stats[s].profit, 0);
  const margin      = totalRev > 0
    ? ((totalProfit / totalRev) * 100).toFixed(1) : '0.0';

  const byDay = {};
  rows.forEach(r => { byDay[r.date] = (byDay[r.date] || 0) + Number(r.total_sale); });
  const bestDay      = Object.entries(byDay).sort((a, b) => b[1] - a[1])[0] || [today, 0];
  const bestDayLabel = new Date(bestDay[0])
    .toLocaleDateString('en-BD', { weekday: 'long' });
  const bestShop     = [...SHOPS].sort((a, b) => stats[b].rev - stats[a].rev)[0];
  const top          = topProduct(rows);

  const wStart = weekStart.toLocaleDateString('en-BD', { day: 'numeric', month: 'long' });
  const wEnd   = now.toLocaleDateString('en-BD',
    { day: 'numeric', month: 'long', year: 'numeric' });

  const revLines    = SHOPS.map(s => `${LABELS[s]}: ৳ ${fmt(stats[s].rev)}`).join('\n');
  const profitLines = SHOPS.map(s => `${LABELS[s]}: ৳ ${fmt(stats[s].profit)}`).join('\n');

  // Weekly debt collected
  const weekDebtRows = debtRows.filter(r => r.paid_date >= weekStartStr && r.paid_date <= today);
  const weekCollected = weekDebtRows.reduce((t, r) => t + Number(r.amount_paid || r.amount_owed || 0), 0);
  const totalOwed = unpaid.reduce((t, r) =>
    t + Number(r.amount_owed || 0) - Number(r.amount_paid || 0), 0);

  reportMessage = `📈 *Weekly Business Report*\n_Week of ${wStart}–${wEnd}_\n${SEP}\n\n`
    + `*Revenue by Shop*\n${revLines}\n\n`
    + `*Profit by Shop*\n${profitLines}\n\n${SEP}\n`
    + `*Combined This Week*\n`
    + `Total Revenue: ৳ ${fmt(totalRev)}\n`
    + `Total Profit: ৳ ${fmt(totalProfit)}\n`
    + `Profit Margin: ${margin}%\n\n`
    + `Best Day: ${bestDayLabel} — ৳ ${fmt(bestDay[1])}\n`
    + `Best Shop: ${LABELS[bestShop]}\n`
    + `Top Product: ${top[0]} — ${top[1]} units\n${SEP}\n`
    + `*Stock Levels*\n${stockLines(stockRows)}\n${SEP}\n`
    + `*Debt This Week*\n`
    + `Collected: ৳ ${fmt(weekCollected)}\n`
    + `Still Outstanding: ৳ ${fmt(totalOwed)} (${unpaid.length} open)\n${SEP}\n`
    + `_— Auto Weekly Report_`;
}

// ─── MONTHLY ───────────────────────────────────────────────────────────
else {
  const prevMonth  = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  const monthStart = prevMonth.toISOString().split('T')[0];
  const monthEnd   = new Date(now.getFullYear(), now.getMonth(), 0)
    .toISOString().split('T')[0];

  const rows        = salesRows.filter(r => r.date >= monthStart && r.date <= monthEnd);
  const stats       = shopStats(rows);
  const totalRev    = SHOPS.reduce((t, s) => t + stats[s].rev,    0);
  const totalProfit = SHOPS.reduce((t, s) => t + stats[s].profit, 0);
  const totalUnits  = SHOPS.reduce((t, s) => t + stats[s].units,  0);
  const margin      = totalRev > 0
    ? ((totalProfit / totalRev) * 100).toFixed(1) : '0.0';
  const vsTarget    = ((totalRev - BUDGET) / BUDGET * 100).toFixed(1);
  const vsLine      = Number(vsTarget) >= 0
    ? `+${vsTarget}% above target ✅` : `${vsTarget}% below target ⚠️`;

  const monthLabel = prevMonth.toLocaleDateString('en-BD',
    { month: 'long', year: 'numeric' });

  const prodMap = {};
  rows.forEach(r => {
    prodMap[r.product_name] = (prodMap[r.product_name] || 0) + Number(r.qty_sold);
  });
  const top3 = Object.entries(prodMap)
    .sort((a, b) => b[1] - a[1]).slice(0, 3)
    .map(([n, q], i) => `${i + 1}. ${n} — ${q} units`)
    .join('\n');

  const rankLines = [...SHOPS]
    .sort((a, b) => stats[b].rev - stats[a].rev)
    .map((s, i) => `${['1st','2nd','3rd'][i]}: ${LABELS[s]} — ৳ ${fmt(stats[s].rev)}`)
    .join('\n');

  const revLines = SHOPS.map(s =>
    `${LABELS[s]}: ৳ ${fmt(stats[s].rev)}`).join('\n');

  // Monthly debt summary
  const monthDebtPaid = debtRows.filter(r =>
    r.paid_date >= monthStart && r.paid_date <= monthEnd
  );
  const monthCollected = monthDebtPaid.reduce((t, r) =>
    t + Number(r.amount_paid || r.amount_owed || 0), 0);
  const totalOwed = unpaid.reduce((t, r) =>
    t + Number(r.amount_owed || 0) - Number(r.amount_paid || 0), 0);

  reportMessage = `🗓️ *Monthly Business Report*\n_${monthLabel}_\n${SEP}\n\n`
    + `*Revenue by Shop*\n${revLines}\n\n${SEP}\n`
    + `*Monthly Summary*\n`
    + `Total Revenue: ৳ ${fmt(totalRev)}\n`
    + `Monthly Target: ৳ ${fmt(BUDGET)}\n`
    + `vs Target: ${vsLine}\n\n`
    + `Total Profit: ৳ ${fmt(totalProfit)}\n`
    + `Profit Margin: ${margin}%\n`
    + `Total Units Sold: ${totalUnits.toLocaleString()}\n${SEP}\n`
    + `*Top 3 Products*\n${top3}\n${SEP}\n`
    + `*Shop Rankings*\n${rankLines}\n${SEP}\n`
    + `*Current Stock*\n${stockLines(stockRows)}\n${SEP}\n`
    + `*Debt Recovery This Month*\n`
    + `Collected: ৳ ${fmt(monthCollected)} (${monthDebtPaid.length} payment${monthDebtPaid.length!==1?'s':''})\n`
    + `Still Outstanding: ৳ ${fmt(totalOwed)}\n`
    + `Open Debts: ${unpaid.length}${overdue.length ? ` | Overdue: ${overdue.length} ⚠️` : ''}\n${SEP}\n`
    + `_— Auto Monthly Report_`;
}

// ─── Return both messages ───────────────────────────────────────────────
return [{ json: { reportMessage, debtMessage, reportType: type } }];

const now = new Date();

const dayOfWeek  = now.getDay();
const dayOfMonth = now.getDate();

const isFirstOfMonth = dayOfMonth === 1;
const isSaturday     = dayOfWeek  === 6;  // ← changed from 1 (Mon) to 6 (Sat)

const reportType = isFirstOfMonth ? 'monthly'
                 : isSaturday     ? 'weekly'
                 : 'daily';

return [{ json: { reportType, triggeredAt: now.toISOString() } }];
